let reminders = [];
try {
    reminders = $('Fetch Expected Reminders').all();
} catch (e) {}

let processedData = [];
try {
    processedData = $('Fetch Processed Data').all();
} catch (e) {}

let rawMessages = [];
try {
    rawMessages = $('Fetch Raw Messages').all();
} catch (e) {}

function normalize(str) {
    if (!str) return "";
    return str.toLowerCase().replace(/[^a-z0-9]/g, "");
}

const outItems = [];

for (const item of reminders) {
    const r = item.json;
    if (!r.report_types) continue;

    const expectedList = r.report_types.split(',').map(s => s.trim()).filter(Boolean);
    if (expectedList.length === 0) continue;

    const assignees = (r.person_phone || "").split(',').map(p => p.trim()).filter(Boolean);
    const assigneeCleanPhones = assignees.map(phone => {
        let clean = phone.replace(/[^0-9]/g, "");
        if (clean.startsWith("0")) clean = clean.substring(1);
        if (clean.length === 10) clean = "91" + clean;
        return clean;
    });

    const whatsappGroupId = r.whatsapp_group_id ? r.whatsapp_group_id.trim() : null;
    const missingReports = [];

    for (const report of expectedList) {
        let submitted = false;
        const rLower = report.toLowerCase();
        let stdCategories = [];
        if (rLower.includes("production")) {
            stdCategories = ['production', 'egg_collection', 'egg_collection_1', 'egg_collection_2', 'egg'];
        } else if (rLower.includes("feed")) {
            stdCategories = ['feed', 'raw_material'];
        } else if (rLower.includes("expense") || rLower.includes("expenditure")) {
            stdCategories = ['expense', 'medicine', 'purchase'];
        } else if (rLower.includes("sale")) {
            stdCategories = ['sales'];
        } else if (rLower.includes("profit") || rLower.includes("p&l") || rLower.includes("p and l")) {
            stdCategories = ['sales', 'expense', 'purchase'];
        }

        for (const pRow of processedData) {
            const p = pRow.json;
            const isFromAssignee = assigneeCleanPhones.some(phone => p.sender && p.sender.includes(phone));
            const isFromGroup = whatsappGroupId && p.group_name && p.group_name === whatsappGroupId;

            if (isFromAssignee || isFromGroup) {
                if (stdCategories.length > 0 && stdCategories.includes(p.category)) {
                    submitted = true;
                    break;
                }
                const normExpected = normalize(report);
                const normNotes = normalize(p.notes);
                if (normExpected && normNotes && normNotes.includes(normExpected)) {
                    submitted = true;
                    break;
                }
            }
        }

        if (submitted) continue;

        for (const mRow of rawMessages) {
            const m = mRow.json;
            const isFromAssignee = assigneeCleanPhones.some(phone => m.sender && m.sender.includes(phone));
            const isFromGroup = whatsappGroupId && m.group_name && m.group_name === whatsappGroupId;

            if (isFromAssignee || isFromGroup) {
                const normExpected = normalize(report);
                const normRawText = normalize(m.raw_text);
                if (normExpected && normRawText && normRawText.includes(normExpected)) {
                    submitted = true;
                    break;
                }
            }
        }

        if (!submitted) {
            missingReports.push(report);
        }
    }

    let messageText = "";
    let chatId = "";
    if (whatsappGroupId) {
        chatId = whatsappGroupId;
    } else if (assignees.length > 0) {
        let clean = assignees[0].replace(/[^0-9]/g, "");
        if (clean.startsWith("0")) clean = clean.substring(1);
        if (clean.length === 10) clean = "91" + clean;
        chatId = clean + "@c.us";
    }

    if (chatId) {
        if (missingReports.length > 0) {
            messageText = "⏰ Sunfra Farms Reminder\n\nPlease submit today's feed, production & Profit & Loss Report so the daily records and reports can be completed accurately.\n\nThank you! 🌱";
            outItems.push({
                json: {
                    chatId: chatId,
                    message: messageText,
                    status: "missing"
                }
            });
        } else {
            messageText = "Daily Report Submission Check:\n\nAll required reports have been submitted successfully today! ✅";
            outItems.push({
                json: {
                    chatId: chatId,
                    message: messageText,
                    status: "complete"
                }
            });
        }
    }
}

return outItems;
